/**
 * @fileoverview DatePicker view - DOM construction, popup rendering, positioning.
 * @module module/DatePicker/view
 */

import { MONTHS_SHORT, WEEKDAYS, SEGMENTS, FORMAT_SEGMENTS,
         SVG, CLS, TEXT, PART } from './constants.js';
import { pad, sameDay, daysInMonth, parseDate, inRange } from './helpers.js';
import razyui from '../../index.js';
import { positionFloating } from '../shared/positionFloating.js';

// ═══════════════════════════════════════
//  DOM Construction
// ═══════════════════════════════════════

/**
 * Build the DatePicker DOM structure around the original input.
 *
 * Creates the container with segmented inputs, optional display label
 * (grid-filter context), icon button, and range separator.
 * Does NOT wire any event listeners - that is handled by events.js.
 *
 * @param {object}  razyui  - core reference
 * @param {object}  config  - component config
 * @param {HTMLInputElement} inputEl - original input (will be hidden)
 * @returns {{ container: HTMLElement, segments: Object, displayLabel: HTMLElement|null, icon: HTMLElement|null }}
 */
export function buildDOM(razyui, config, inputEl) {
    const type  = config.type;
    const segs  = FORMAT_SEGMENTS[type];
    const isRange = config.mode === 'range';
    const hasDate = type !== 'time';

    // ── Container ──
    const container = razyui.el('div', {
        className: CLS.CONTAINER,
        role: 'group',
        'aria-label': TEXT.PICKER_GROUP
    });
    PART.CONTAINER.apply(container);

    let displayLabel = null;
    const segments = {};
    let icon = null;

    // ── Render-context modifier ──
    if (config.renderContext) {
        container.addClass(`is-${config.renderContext}`);

        if (config.renderContext === 'grid-filter') {
            const ph = type === 'month' ? 'YYYY-MM'
                     : type === 'datetime' ? 'YYYY-MM-DD HH:mm'
                     : 'YYYY-MM-DD';
            displayLabel = razyui.el('span', {
                className: CLS.DISPLAY,
                textContent: '',
                'data-placeholder': isRange ? `${ph} TO ${ph}` : ph
            });
            PART.DISPLAY.apply(displayLabel);
            container.append(displayLabel);
        }
    }

    // ── Build segment group (start / end) ──
    const isGridFilter = config.renderContext === 'grid-filter';
    const buildSegmentGroup = (prefix) => {
        const section = razyui.el('div', { className: CLS.SECTION });
        PART.SECTION.apply(section);

        // Calendar / clock icon (first group only, hidden in grid-filter)
        if (!isGridFilter) {
            if (hasDate && !prefix) {
                const btn = razyui.el('button', {
                    type: 'button',
                    className: CLS.ICON,
                    tabIndex: -1,
                    'aria-label': TEXT.OPEN_CALENDAR,
                    innerHTML: SVG.CALENDAR
                });
                PART.ICON.apply(btn);
                section.append(btn);
                icon = btn;
            } else if (type === 'time' && !prefix) {
                const btn = razyui.el('button', {
                    type: 'button',
                    className: CLS.ICON,
                    tabIndex: -1,
                    'aria-label': TEXT.TIME_LABEL,
                    innerHTML: SVG.CLOCK
                });
                PART.ICON.apply(btn);
                section.append(btn);
                icon = btn;
            }
        }

        const dateSegs = segs.filter(s => ['year', 'month', 'day'].includes(s));
        const timeSegs = segs.filter(s => ['hour', 'minute'].includes(s));

        const buildInputs = (segList, sep) => {
            segList.forEach((segType, i) => {
                if (i > 0) {
                    const span = razyui.el('span', {
                        className: CLS.SEP,
                        textContent: sep
                    });
                    PART.SEP.apply(span);
                    section.append(span);
                }
                const inp = razyui.el('input', {
                    type: 'text',
                    className: `${CLS.SEG} ${CLS.SEG}-${segType}`,
                    'data-seg': segType,
                    maxLength: SEGMENTS[segType].len,
                    size: SEGMENTS[segType].len,
                    'aria-label': segType,
                    placeholder: segType === 'year' ? 'YYYY' : segType.substring(0, 2).toUpperCase(),
                    autocomplete: 'off'
                });
                PART.SEG.apply(inp);

                const key = prefix ? `${prefix}_${segType}` : segType;
                segments[key] = inp[0];
                section.append(inp);
            });
        };

        if (dateSegs.length) {
            buildInputs(dateSegs, '/');
        }
        if (timeSegs.length && dateSegs.length) {
            const spacer = razyui.el('span', {
                className: CLS.SEP_SPACE,
                innerHTML: '&nbsp;'
            });
            section.append(spacer);
        }
        if (timeSegs.length) {
            buildInputs(timeSegs, ':');
        }

        return section;
    };

    // Start section
    container.append(buildSegmentGroup(''));

    // Range mode: separator + end section
    if (isRange && type !== 'time') {
        const rangeSep = razyui.el('span', {
            className: CLS.RANGE_SEP,
            textContent: TEXT.RANGE_SEP
        });
        PART.RANGE_SEP.apply(rangeSep);
        container.append(rangeSep)
                 .append(buildSegmentGroup('end'));
    }

    // Insert into DOM
    razyui(inputEl).css('display', 'none');
    inputEl.parentNode.insertBefore(container[0], inputEl.nextSibling);

    return { container: container[0], segments, displayLabel: displayLabel ? displayLabel[0] : null, icon: icon ? icon[0] : null };
}

// ═══════════════════════════════════════
//  Popup Creation & Rendering
// ═══════════════════════════════════════

/**
 * Create the popup element.
 *
 * @returns {HTMLDivElement}
 */
export function createPopup() {
    const popup = razyui.el('div', {
        className: `${CLS.CONTAINER} ${CLS.POPUP}`,
        role: 'dialog',
        'aria-label': TEXT.CALENDAR_DIALOG
    });
    PART.POPUP.apply(popup);
    return popup[0];
}

/**
 * Render popup content - header navigation, grid body, optional today footer.
 *
 * @param {object}      razyui - core reference (for spell)
 * @param {HTMLElement}  popup
 * @param {object}       ctx
 * @param {Date}         ctx.viewDate
 * @param {string}       ctx.popupView   - 'year' | 'month' | 'day'
 * @param {string}       ctx.type        - format type
 * @param {object}       ctx.config      - component config (min, max, …)
 * @param {string}       ctx.mode        - 'single' | 'range'
 * @param {Date|null}    ctx.currentStart
 * @param {Date|null}    ctx.currentEnd
 * @param {Date|null}    ctx.rangeAnchor
 * @param {Date|null}    ctx.rangeAnchor
 */
export function renderPopup(razyui, popup, ctx) {
    const $popup = razyui(popup);
    $popup.html('');

    const { viewDate: vd, popupView: view } = ctx;

    // ── Header ──
    const hdom = razyui.spell(
        `div.${CLS.POPUP_HEADER}(button.${CLS.NAV},button.${CLS.TITLE},button.${CLS.NAV})`,
        true
    );
    const header  = hdom[0];
    PART.POPUP_HEADER.apply(header);
    const navBtns = hdom.find('.' + CLS.NAV);
    navBtns.forEach(b => PART.NAV.apply(b));

    const prevBtn = navBtns[0];
    prevBtn.type = 'button';
    razyui(prevBtn).html(SVG.PREV).setAttr({'aria-label': TEXT.PREVIOUS});

    const nextBtn = navBtns[1];
    nextBtn.type = 'button';
    razyui(nextBtn).html(SVG.NEXT).setAttr({'aria-label': TEXT.NEXT});

    const titleBtn = hdom.find('.' + CLS.TITLE)[0];
    PART.TITLE.apply(titleBtn);
    const $titleBtn = razyui(titleBtn);
    titleBtn.type = 'button';

    if (view === 'day') {
        $titleBtn.text(`${MONTHS_SHORT[vd.getMonth()]} ${vd.getFullYear()}`);
        titleBtn.dataset.drill = 'month';
    } else if (view === 'month') {
        $titleBtn.text(`${vd.getFullYear()}`);
        titleBtn.dataset.drill = 'year';
    } else if (view === 'year') {
        const startYear = vd.getFullYear() - (vd.getFullYear() % 16);
        $titleBtn.text(`${startYear} \u2013 ${startYear + 15}`).css('cursor', 'default');
    }

    razyui(header).append(prevBtn).append(titleBtn).append(nextBtn);
    $popup.append(header);

    // ── Body ──
    const body = razyui.spell(`div.${CLS.POPUP_BODY}.is-${view}`, true)[0];
    PART.POPUP_BODY.apply(body);
    $popup.append(body);

    if (view === 'day') {
        renderDayGrid(body, ctx);
    } else if (view === 'month') {
        renderMonthGrid(body, ctx);
    } else if (view === 'year') {
        renderYearGrid(body, ctx);
    }

    // ── Today button (day view only) ──
    if (view === 'day') {
        const fdom = razyui.spell(`div.${CLS.POPUP_FOOTER}(button.${CLS.TODAY_BTN})`, true);
        PART.POPUP_FOOTER.apply(fdom[0]);
        const todayBtn = fdom.find('.' + CLS.TODAY_BTN)[0];
        PART.TODAY_BTN.apply(todayBtn);
        todayBtn.type = 'button';
        razyui(todayBtn).text(TEXT.TODAY);
        $popup.append(fdom[0]);
    }
}

// ═══════════════════════════════════════
//  Grid Renderers
// ═══════════════════════════════════════

/**
 * Render the day grid - weekday headers + numbered day cells.
 */
function renderDayGrid(body, ctx) {
    const { viewDate: vd, config, mode, currentStart, currentEnd } = ctx;
    const year      = vd.getFullYear();
    const month     = vd.getMonth();
    const firstDay  = new Date(year, month, 1).getDay();
    const totalDays = daysInMonth(year, month);
    const minDate   = parseDate(config.min);
    const maxDate   = parseDate(config.max);
    const isRange   = mode === 'range';
    const today     = new Date();

    // Weekday headers
    const $body = razyui(body);
    WEEKDAYS.forEach(w => {
        const el = razyui.el('div', {
            className: CLS.WEEKDAY,
            textContent: w
        });
        PART.WEEKDAY.apply(el);
        $body.append(el[0]);
    });

    // Empty cells before first day
    for (let i = 0; i < firstDay; i++) {
        const el = razyui.el('div', { className: CLS.EMPTY });
        PART.EMPTY.apply(el);
        $body.append(el[0]);
    }

    // Day cells
    for (let d = 1; d <= totalDays; d++) {
        const date = new Date(year, month, d);
        const cell = razyui.el('button', {
            type: 'button',
            className: CLS.DAY,
            textContent: d,
            'data-year': year,
            'data-month': month,
            'data-day': d
        });
        PART.DAY.apply(cell);

        // Today
        if (sameDay(date, today)) {
            cell.addClass(CLS.TODAY);
        }

        // Selected
        if (sameDay(date, currentStart)) {
            cell.addClass(CLS.SELECTED);
            if (isRange) cell.addClass(CLS.RANGE_START);
        }
        if (isRange && sameDay(date, currentEnd)) {
            cell.addClass(CLS.SELECTED, CLS.RANGE_END);
        }

        // In range
        if (isRange && currentStart && currentEnd &&
            inRange(date, currentStart, currentEnd) &&
            !sameDay(date, currentStart) && !sameDay(date, currentEnd)) {
            cell.addClass(CLS.IN_RANGE);
        }

        // Disabled by min/max
        if ((minDate && date < new Date(minDate.getFullYear(), minDate.getMonth(), minDate.getDate())) ||
            (maxDate && date > new Date(maxDate.getFullYear(), maxDate.getMonth(), maxDate.getDate()))) {
            cell.addClass(CLS.OUT_OF_RANGE);
            cell.prop('disabled', true);
        }

        $body.append(cell[0]);
    }
}

/**
 * Render the month grid (12 month cells).
 */
function renderMonthGrid(body, ctx) {
    const { viewDate: vd, type, currentStart } = ctx;
    const $body = razyui(body);

    MONTHS_SHORT.forEach((name, i) => {
        const cell = razyui.el('button', {
            type: 'button',
            className: CLS.MONTH_CELL,
            textContent: name,
            'data-month-index': i,
            'data-year': vd.getFullYear()
        });
        PART.MONTH_CELL.apply(cell);

        if (currentStart && currentStart.getFullYear() === vd.getFullYear() &&
            currentStart.getMonth() === i) {
            cell.addClass(CLS.SELECTED);
        }

        $body.append(cell[0]);
    });
}

/**
 * Render the year grid (16-year range).
 */
function renderYearGrid(body, ctx) {
    const { viewDate: vd, currentStart } = ctx;
    const $body = razyui(body);
    const startYear = vd.getFullYear() - (vd.getFullYear() % 16);

    for (let y = startYear; y < startYear + 16; y++) {
        const cell = razyui.el('button', {
            type: 'button',
            className: CLS.YEAR_CELL,
            textContent: y,
            'data-year': y
        });
        PART.YEAR_CELL.apply(cell);

        if (currentStart && currentStart.getFullYear() === y) {
            cell.addClass(CLS.SELECTED);
        }

        $body.append(cell[0]);
    }
}

// ═══════════════════════════════════════
//  Popup Positioning
// ═══════════════════════════════════════

/**
 * Position the popup below (or flip above) the container.
 *
 * @param {HTMLElement} popup
 * @param {HTMLElement} container
 * @param {number}      gap - pixel gap between container and popup
 */
export function positionPopup(popup, container, gap) {
    positionFloating(popup, container, {
        strategy: 'fixed',
        gap,
        flip:     true,
        width:    'auto',
    });
}

// ═══════════════════════════════════════
//  Range Preview
// ═══════════════════════════════════════

/**
 * Update the hover preview in range mode.
 *
 * @param {HTMLElement} popup
 * @param {Date}        viewDate
 * @param {Date}        anchor
 * @param {Date}        hover
 */
export function updateRangePreview(popup, viewDate, anchor, hover) {
    if (!popup || !anchor || !hover) return;

    const cells = razyui(popup).find('.' + CLS.DAY);
    const vd = viewDate;

    cells.each(cell => {
        const d    = parseInt(cell.textContent);
        const date = new Date(vd.getFullYear(), vd.getMonth(), d);
        const $cell = razyui(cell);

        $cell.removeClass(CLS.IN_RANGE, CLS.RANGE_START, CLS.RANGE_END, CLS.SELECTED);

        if (sameDay(date, anchor)) {
            $cell.addClass(CLS.SELECTED, CLS.RANGE_START);
        } else if (sameDay(date, hover)) {
            $cell.addClass(CLS.SELECTED, CLS.RANGE_END);
        } else if (inRange(date, anchor, hover)) {
            $cell.addClass(CLS.IN_RANGE);
        }
    });
}
