/**
 * @fileoverview DatePicker component - modular entry point.
 *
 * Orchestrates sub-modules:
 *   constants.js - months, weekdays, segment defs, SVG icons, CSS classes, defaults
 *   helpers.js   - pad, sameDay, daysInMonth, parseDate, formatDate, inRange, clampDate
 *   state.js     - reactive state creation + disabled effect
 *   view.js      - DOM construction, popup rendering, positioning, range preview
 *   events.js    - centralised event binding (AbortController cleanup)
 *
 * @module module/DatePicker
 */

import { default as razyui } from '../../index.js';
import { zIndexRegistry } from '../shared/ZIndexRegistry.js';

import { SEGMENTS, FORMAT_SEGMENTS, CLS, DEFAULTS }          from './constants.js';
import { pad, daysInMonth, parseDate, formatDate }            from './helpers.js';
import { createReactiveState, wireDisabledEffect }            from './state.js';
import { buildDOM, createPopup, renderPopup,
         positionPopup, updateRangePreview }                  from './view.js';
import { bindEvents, attachPopupOutsideClick,
         bindPopupKeydown, bindPopupEvents }                  from './events.js';
import { emitEvent } from '../shared/emitEvent.js';

/**
 * DatePicker - v2 modular rewrite
 *
 * A date/time input component with calendar popup. Enhances a native <input>
 * into a segmented date/time field with a dropdown calendar picker.
 *
 * Modes:
 *   - **single** - pick one date
 *   - **range**  - pick start & end dates (period selection)
 *
 * Format types:
 *   - date     - YYYY-MM-DD
 *   - month    - YYYY-MM
 *   - datetime - YYYY-MM-DD HH:mm
 *   - time     - HH:mm
 *
 * Reactive state via razyui.state(); property setters on getControl().
 *
 * Features:
 *   - Segmented input fields (year/month/day/hour/minute)
 *   - Calendar popup (year grid, month grid, day grid)
 *   - Period / range selection with visual hover preview
 *   - Mouse-wheel increment on segments
 *   - Min / max date boundaries
 *   - Keyboard navigation within calendar
 *   - ARIA accessible
 *   - Callbacks: onChange, onOpen, onClose
 *   - Programmatic API: getControl(), destroy()
 *
 * HTML pattern:
 *   <input type="text" id="my-date">
 *
 * @class DatePicker
 * @param {string|Element} selector - The DOM selector or element to attach the DatePicker to.
 * @param {object}   [config] - Configuration options for the DatePicker.
 * @param {string}   [config.type]       - 'date' | 'month' | 'datetime' | 'time' (default 'date')
 * @param {string}   [config.mode]       - 'single' | 'range' (default 'single')
 * @param {string}   [config.value]      - initial value e.g. '2025-06-15' or '2025-06-01 ~ 2025-06-30'
 * @param {string}   [config.min]        - minimum date YYYY-MM-DD
 * @param {string}   [config.max]        - maximum date YYYY-MM-DD
 * @param {string}   [config.placeholder] - placeholder text
 * @param {function} [config.onChange]    - Callback function triggered on value change: (value: string, dates: Date|Date[]) => void
 * @param {function} [config.onOpen]     - Callback function triggered when popup opens: () => void
 * @param {function} [config.onClose]    - Callback function triggered when popup closes: () => void
 */
const DatePicker = class {
    #input = null;
    #destroyed = false;
    #container = null;
    #segments = {};       // {type: inputElement}
    #popup = null;
    #config = {};
    #stateRef = null;
    #setState = null;
    #outsideAC = null;   // popup outside-click + keydown
    #popupEventsAC = null;     // delegated popup events
    #eventAC = null;          // static segment/container events
    #displayLabel = null;      // inline mode: simplified text display
    #popupView = 'day';        // 'year' | 'month' | 'day'
    #viewDate = null;          // Date shown in calendar header (navigation context)
    #hoverDate = null;         // for range hover preview
    #rangeAnchor = null;       // first selected date in range mode

    static #counter = 0;

    constructor(selector, config = {}) {
        this.#config = { ...DEFAULTS, ...config };

        // Resolve JIT spacing tokens
        this.#config.dropdownGap = razyui.JIT.TOKEN.spacePx(this.#config.dropdownGap);

        // Normalize type
        if (!FORMAT_SEGMENTS[this.#config.type]) {
            this.#config.type = DEFAULTS.type;
        }

        // Resolve element
        const el = razyui.isStr(selector) ? razyui(selector)[0] : selector;
        if (!el) {
            console.warn('DatePicker: element not found \u2192', selector);
            return;
        }
        this.#input = el;
        if (config.name) el.name = config.name;

        this.#init();
    }

    // ────────────────────────────────────────────
    // Initialisation
    // ────────────────────────────────────────────

    #init() {
        const cfg    = this.#config;
        const type   = cfg.type;
        const hasDate = type !== 'time';
        ++DatePicker.#counter;

        // ── Build DOM ──
        const domRefs = buildDOM(razyui, cfg, this.#input);
        this.#container    = domRefs.container;
        this.#segments     = domRefs.segments;
        this.#displayLabel = domRefs.displayLabel;

        // ── Reactive state ──
        const stateSet = createReactiveState(razyui.state, this.#input);
        const [stateRef, setState] = stateSet;
        this.#stateRef = stateRef;
        this.#setState  = setState;

        wireDisabledEffect(stateSet, this.#container, this.#segments);

        // ── Bind events ──
        const self    = this;
        const segKeys = () => self.#getSegmentKeys();

        this.#eventAC = bindEvents({
            container:    this.#container,
            segments:     this.#segments,
            displayLabel: this.#displayLabel,
            icon:         domRefs.icon,
        }, {
            onContainerClick: (e) => {
                if (stateRef.disabled) return;
                if (cfg.renderContext === 'grid-filter') {
                    self.#togglePopup();
                    return;
                }
                if (e.target === self.#container ||
                    razyui(e.target).hasClass(CLS.SECTION)) {
                    const firstKey = segKeys()[0];
                    if (firstKey) self.#segments[firstKey].focus();
                }
            },
            onDisplayLabelClick: () => {
                if (!stateRef.disabled) self.#togglePopup();
            },
            onIconClick: () => {
                if (stateRef.disabled) return;
                if (hasDate) {
                    self.#togglePopup();
                } else {
                    // Time mode -> focus the first segment input
                    const allKeys = segKeys();
                    if (allKeys.length > 0) self.#segments[allKeys[0]]?.focus();
                }
            },
            onSegmentWheel: (e, key) => {
                e.preventDefault();
                if (stateRef.disabled) return;
                const delta = e.deltaY < 0 ? 1 : -1;
                self.#stepSegment(key, delta);
            },
            onSegmentFocus: (inp, key) => {
                if (stateRef.disabled) { inp.blur(); return; }
                inp.select();
            },
            onSegmentInput: (inp, key) => {
                if (stateRef.disabled) { inp.value = ''; return; }
                const segType = key.replace(/^end_/, '');
                const maxLen  = SEGMENTS[segType].len;
                if (inp.value.length >= maxLen) {
                    self.#validateSegment(key);
                    // Move to next segment
                    const allKeys = segKeys();
                    const idx = allKeys.indexOf(key);
                    if (idx < allKeys.length - 1) {
                        self.#segments[allKeys[idx + 1]].focus();
                    }
                }
            },
            onSegmentBlur: (inp, key) => {
                self.#validateSegment(key);
                // Delay to check if focus moved outside container
                setTimeout(() => {
                    if (!self.#container.contains(document.activeElement)) {
                        self.#syncValue();
                    }
                }, 50);
            },
            onSegmentKeydown: (e, inp, key) => {
                if (stateRef.disabled) return;
                if (e.key === 'ArrowUp') {
                    e.preventDefault();
                    self.#stepSegment(key, 1);
                } else if (e.key === 'ArrowDown') {
                    e.preventDefault();
                    self.#stepSegment(key, -1);
                } else if (e.key === 'ArrowRight' && inp.selectionStart === inp.value.length) {
                    const allKeys = segKeys();
                    const idx = allKeys.indexOf(key);
                    if (idx < allKeys.length - 1) {
                        e.preventDefault();
                        self.#segments[allKeys[idx + 1]].focus();
                    }
                } else if (e.key === 'ArrowLeft' && inp.selectionStart === 0) {
                    const allKeys = segKeys();
                    const idx = allKeys.indexOf(key);
                    if (idx > 0) {
                        e.preventDefault();
                        self.#segments[allKeys[idx - 1]].focus();
                    }
                } else if (e.key === 'Enter' && hasDate) {
                    e.preventDefault();
                    self.#togglePopup();
                } else if (e.key === 'Escape') {
                    self.#closePopup();
                }
                // Block non-numeric
                if (e.key.length === 1 && !/\d/.test(e.key) && !e.ctrlKey && !e.metaKey) {
                    e.preventDefault();
                }
            },
        });

        // ── Set initial value ──
        const initialValue = cfg.value || this.#input.value || '';
        if (initialValue) {
            this.#parseAndSetValue(initialValue);
        } else {
            const now = new Date();
            this.#viewDate = new Date(now.getFullYear(), now.getMonth(), 1);
            if (this.#config.defaultToday) {
                this.#setSegmentsFromDate(now, '');
                this.#syncValue();
            }
        }
    }

    // ────────────────────────────────────────────
    // Segment helpers
    // ────────────────────────────────────────────

    #getSegmentKeys() {
        return Object.keys(this.#segments);
    }

    #validateSegment(key) {
        const inp = this.#segments[key];
        if (!inp) return;
        const segType = key.replace(/^end_/, '');
        const def = SEGMENTS[segType];
        let val = parseInt(inp.value) || def.min;

        // Dynamic max for day
        let max = def.max;
        if (segType === 'day') {
            const prefix = key.startsWith('end_') ? 'end_' : '';
            const y = parseInt(this.#segments[prefix + 'year']?.value) || new Date().getFullYear();
            const m = parseInt(this.#segments[prefix + 'month']?.value) || 1;
            max = daysInMonth(y, m - 1);
        }

        val = razyui.clamp(val, def.min, max);
        inp.value = pad(val, def.len);
    }

    #stepSegment(key, delta) {
        const inp = this.#segments[key];
        if (!inp) return;
        const segType = key.replace(/^end_/, '');
        const def = SEGMENTS[segType];
        let val = parseInt(inp.value) || def.min;
        val += delta;

        let max = def.max;
        if (segType === 'day') {
            const prefix = key.startsWith('end_') ? 'end_' : '';
            const y = parseInt(this.#segments[prefix + 'year']?.value) || new Date().getFullYear();
            const m = parseInt(this.#segments[prefix + 'month']?.value) || 1;
            max = daysInMonth(y, m - 1);
        }

        // Wrap around
        if (val > max) val = def.min;
        if (val < def.min) val = max;

        inp.value = pad(val, def.len);
        this.#syncValue();
    }

    #getDateFromSegments(prefix = '') {
        const p    = prefix ? prefix + '_' : '';
        const type = this.#config.type;
        const y  = parseInt(this.#segments[p + 'year']?.value);
        const mo = parseInt(this.#segments[p + 'month']?.value);
        const d  = parseInt(this.#segments[p + 'day']?.value);
        const h  = parseInt(this.#segments[p + 'hour']?.value) || 0;
        const mi = parseInt(this.#segments[p + 'minute']?.value) || 0;

        if (type === 'time') {
            return new Date(2000, 0, 1, h, mi);
        }
        if (!y || !mo) return null;
        return new Date(y, mo - 1, d || 1, h, mi);
    }

    #setSegmentsFromDate(date, prefix = '') {
        if (!date) return;
        const p = prefix ? prefix + '_' : '';

        if (this.#segments[p + 'year'])   this.#segments[p + 'year'].value   = pad(date.getFullYear(), 4);
        if (this.#segments[p + 'month'])  this.#segments[p + 'month'].value  = pad(date.getMonth() + 1);
        if (this.#segments[p + 'day'])    this.#segments[p + 'day'].value    = pad(date.getDate());
        if (this.#segments[p + 'hour'])   this.#segments[p + 'hour'].value   = pad(date.getHours());
        if (this.#segments[p + 'minute']) this.#segments[p + 'minute'].value = pad(date.getMinutes());
    }

    // ────────────────────────────────────────────
    // Value sync
    // ────────────────────────────────────────────

    #syncValue() {
        const type    = this.#config.type;
        const isRange = this.#config.mode === 'range' && type !== 'time';
        const startDate = this.#getDateFromSegments('');
        let val = '';

        if (isRange) {
            const endDate = this.#getDateFromSegments('end');
            if (startDate) val = formatDate(startDate, type);
            if (endDate) val += ' ~ ' + formatDate(endDate, type);
            this.#setState({ value: val, startDate, endDate });
        } else {
            val = formatDate(startDate, type);
            this.#setState({ value: val, startDate });
        }
        this.#input.value    = val;

        // Update inline display label
        if (this.#displayLabel) {
            const $label = razyui(this.#displayLabel);
            if (val) {
                $label.text(val.replace(/~/g, 'TO')).addClass(CLS.HAS_VALUE);
            } else {
                $label.text('').removeClass(CLS.HAS_VALUE);
            }
        }

        if (isRange) {
            emitEvent(this.#container, 'change', { value: val, dates: [startDate, this.#stateRef.endDate] });
        } else {
            emitEvent(this.#container, 'change', { value: val, date: startDate });
        }

        if (typeof this.#config.onChange === 'function') {
            if (isRange) {
                this.#config.onChange.call(this, val, [startDate, this.#stateRef.endDate]);
            } else {
                this.#config.onChange.call(this, val, startDate);
            }
        }
    }

    #parseAndSetValue(str) {
        const type    = this.#config.type;
        const isRange = this.#config.mode === 'range' && type !== 'time';

        if (isRange) {
            const parts = str.split('~').map(s => s.trim());
            const start = parseDate(parts[0]);
            const end   = parts[1] ? parseDate(parts[1]) : null;
            if (start) {
                this.#setSegmentsFromDate(start, '');
                this.#viewDate = new Date(start.getFullYear(), start.getMonth(), 1);
            }
            if (end) {
                this.#setSegmentsFromDate(end, 'end');
            }
        } else {
            const d = parseDate(str);
            if (d) {
                this.#setSegmentsFromDate(d, '');
                if (type !== 'time') {
                    this.#viewDate = new Date(d.getFullYear(), d.getMonth(), 1);
                }
            }
        }

        if (!this.#viewDate) {
            const now = new Date();
            this.#viewDate = new Date(now.getFullYear(), now.getMonth(), 1);
        }

        this.#syncValue();
    }

    // ────────────────────────────────────────────
    // Calendar popup
    // ────────────────────────────────────────────

    #togglePopup() {
        if (this.#stateRef.disabled) return;
        if (this.#popup) {
            this.#closePopup();
        } else {
            this.#openPopup();
        }
    }

    #openPopup() {
        if (this.#popup) return;
        if (this.#config.type === 'time') return;

        this.#rangeAnchor = null;
        this.#hoverDate   = null;

        const popup = createPopup();
        this.#popup = popup;
        this.#popupView = this.#config.type === 'month' ? 'month' : 'day';

        // Sync viewDate from current segment values
        const currentStart = this.#getDateFromSegments('');
        if (currentStart && currentStart.getFullYear() > 1900) {
            this.#viewDate = new Date(currentStart.getFullYear(), currentStart.getMonth(), 1);
        }

        this.#renderPopupContent();

        // ── Delegated popup events ──
        const self = this;
        this.#popupEventsAC = bindPopupEvents(popup, {
            onPrev: () => {
                const view = self.#popupView;
                const vd   = self.#viewDate;
                if (view === 'day') {
                    self.#viewDate = new Date(vd.getFullYear(), vd.getMonth() - 1, 1);
                } else if (view === 'month') {
                    self.#viewDate = new Date(vd.getFullYear() - 1, vd.getMonth(), 1);
                } else if (view === 'year') {
                    self.#viewDate = new Date(vd.getFullYear() - 16, vd.getMonth(), 1);
                }
                self.#renderPopupContent();
            },
            onNext: () => {
                const view = self.#popupView;
                const vd   = self.#viewDate;
                if (view === 'day') {
                    self.#viewDate = new Date(vd.getFullYear(), vd.getMonth() + 1, 1);
                } else if (view === 'month') {
                    self.#viewDate = new Date(vd.getFullYear() + 1, vd.getMonth(), 1);
                } else if (view === 'year') {
                    self.#viewDate = new Date(vd.getFullYear() + 16, vd.getMonth(), 1);
                }
                self.#renderPopupContent();
            },
            onTitleClick: (newView) => {
                self.#popupView = newView;
                self.#renderPopupContent();
            },
            onSelectDate: (date) => {
                self.#selectDate(date);
            },
            onDayHover: (date) => {
                if (self.#rangeAnchor) {
                    self.#hoverDate = date;
                    updateRangePreview(self.#popup, self.#viewDate, self.#rangeAnchor, self.#hoverDate);
                }
            },
            onTodayClick: () => {
                const today = new Date();
                self.#selectDate(today);
                self.#viewDate = new Date(today.getFullYear(), today.getMonth(), 1);
                self.#renderPopupContent();
            },
            onMonthSelect: (monthIndex, year) => {
                if (self.#config.type === 'month') {
                    self.#selectDate(new Date(year, monthIndex, 1));
                } else {
                    self.#viewDate = new Date(year, monthIndex, 1);
                    self.#popupView = 'day';
                    self.#renderPopupContent();
                }
            },
            onYearDrillDown: (year) => {
                self.#viewDate = new Date(year, self.#viewDate.getMonth(), 1);
                self.#popupView = 'month';
                self.#renderPopupContent();
            },
        });

        // Position
        popup.style.visibility = 'hidden';
        razyui(document.body).append(popup);
        zIndexRegistry.acquire(popup);

        // Inherit data-theme from nearest themed ancestor so dark mode works
        const themed = this.#container.closest('[data-theme]');
        if (themed) {
            popup.setAttribute('data-theme', themed.getAttribute('data-theme'));
        }

        // Defer positioning to next frame so JIT CSS rules are injected
        // (cssJIT injects rules asynchronously via microtask)
        requestAnimationFrame(() => {
            if (!this.#popup) return;           // closed before frame
            positionPopup(popup, this.#container, this.#config.dropdownGap);
            popup.style.visibility = '';
        });

        // Outside click + popup keydown
        this.#outsideAC = attachPopupOutsideClick(popup, this.#container, () => {
            this.#closePopup();
        });
        bindPopupKeydown(popup, () => {
            this.#closePopup();
            const firstKey = this.#getSegmentKeys()[0];
            if (firstKey) this.#segments[firstKey].focus();
        }, this.#outsideAC);

        this.#setState({ open: true });
        if (typeof this.#config.onOpen === 'function') {
            this.#config.onOpen.call(this);
        }
    }

    #closePopup() {
        if (!this.#popup) return;
        zIndexRegistry.release(this.#popup);
        this.#popup.remove();
        this.#popup = null;
        this.#outsideAC?.abort();
        this.#outsideAC = null;
        this.#popupEventsAC?.abort();
        this.#popupEventsAC = null;
        this.#setState({ open: false });
        if (typeof this.#config.onClose === 'function') {
            this.#config.onClose.call(this);
        }
    }

    #renderPopupContent() {
        renderPopup(razyui, this.#popup, {
            viewDate:     this.#viewDate,
            popupView:    this.#popupView,
            type:         this.#config.type,
            config:       this.#config,
            mode:         this.#config.mode === 'range' && this.#config.type !== 'time' ? 'range' : 'single',
            currentStart: this.#getDateFromSegments(''),
            currentEnd:   this.#config.mode === 'range' ? this.#getDateFromSegments('end') : null,
            rangeAnchor:  this.#rangeAnchor,
        });
    }

    // ────────────────────────────────────────────
    // Date selection
    // ────────────────────────────────────────────

    #selectDate(date) {
        const isRange = this.#config.mode === 'range' && this.#config.type !== 'time';

        if (isRange) {
            if (!this.#rangeAnchor) {
                // First click: set anchor
                this.#rangeAnchor = date;
                this.#setSegmentsFromDate(date, '');
                // Clear end
                const endKeys = this.#getSegmentKeys().filter(k => k.startsWith('end_'));
                endKeys.forEach(k => { this.#segments[k].value = ''; });
                this.#syncValue();
                this.#renderPopupContent();
            } else {
                // Second click: complete range
                let start = this.#rangeAnchor;
                let end   = date;
                if (start > end) [start, end] = [end, start];
                this.#setSegmentsFromDate(start, '');
                this.#setSegmentsFromDate(end, 'end');
                this.#rangeAnchor = null;
                this.#hoverDate   = null;
                this.#syncValue();
                this.#closePopup();
            }
        } else {
            this.#setSegmentsFromDate(date, '');
            this.#syncValue();
            if (this.#config.type !== 'datetime') {
                this.#closePopup();
            } else {
                this.#renderPopupContent();
            }
        }
    }

    // ────────────────────────────────────────────
    // Public API
    // ────────────────────────────────────────────

    /** Get current value string. */
    get value() {
        return this.#stateRef.value;
    }

    /** Set value from string. */
    set value(v) {
        if (this.#stateRef.disabled) return;
        this.#parseAndSetValue(v);
    }

    /** Get start date as Date object. */
    get startDate() {
        return this.#stateRef.startDate;
    }

    /** Get end date (range mode). */
    get endDate() {
        return this.#stateRef.endDate;
    }

    /** Open calendar popup. */
    open() {
        if (this.#stateRef.disabled) return;
        this.#openPopup();
    }

    /** Close calendar popup. */
    close() {
        this.#closePopup();
    }

    toggle() {
        if (this.#stateRef.disabled) return;
        this.#popup ? this.close() : this.open();
    }

    get isOpen() { return !!this.#popup; }

    /** Enable or disable. */
    setDisabled(disabled) {
        this.#setState({ disabled: !!disabled });
        this.#input.disabled = !!disabled;
        Object.values(this.#segments).forEach(inp => inp.disabled = !!disabled);
        this.#container.setAttribute('aria-disabled', String(!!disabled));
        if (disabled) this.#closePopup();
    }

    setInvalid(invalid) {
        this.#container.classList.toggle(CLS.INVALID, !!invalid);
        this.#container[invalid ? 'setAttribute' : 'removeAttribute']('aria-invalid', 'true');
    }

    focus() {
        const keys = Object.keys(this.#segments);
        if (keys.length) this.#segments[keys[0]]?.focus();
    }
    blur() {
        const active = Object.values(this.#segments).find(s => s === document.activeElement);
        if (active) active.blur();
    }

    /** Clear all segment values and reset the component. */
    clear() {
        for (const inp of Object.values(this.#segments)) {
            inp.value = '';
        }
        this.#setState({ value: '', startDate: null, endDate: null });
        this.#input.value        = '';
        if (this.#displayLabel) {
            razyui(this.#displayLabel).text('').removeClass(CLS.HAS_VALUE);
        }
        if (typeof this.#config.onChange === 'function') {
            this.#config.onChange.call(this, '', null);
        }
    }

    /**
     * Return a control object with property setters.
     */
    getControl() {
        const self = this;
        return {
            get value() { return self.value; },
            set value(v) { self.value = v; },
            get startDate() { return self.startDate; },
            get endDate() { return self.endDate; },
            get disabled() { return self.#stateRef.disabled; },
            set disabled(v) { self.setDisabled(v); },
            get min() { return self.#config.min; },
            set min(v) { self.#config.min = v; },
            get max() { return self.#config.max; },
            set max(v) { self.#config.max = v; },
            get required() { return self.#input.required; },
            set required(v) { self.#input.required = !!v; self.#container.setAttribute('aria-required', String(!!v)); },
            open:   () => self.open(),
            close:  () => self.close(),
            toggle: () => self.toggle(),
            get isOpen() { return self.isOpen; },
            setInvalid:        (v) => self.setInvalid(v),
            checkValidity:     () => self.#input.checkValidity(),
            reportValidity:    () => self.#input.reportValidity(),
            setCustomValidity: (m) => { self.#input.setCustomValidity(m || ''); self.setInvalid(!!m); },
            get label() { return self.#container.getAttribute('aria-label'); },
            set label(v) { v ? self.#container.setAttribute('aria-label', v) : self.#container.removeAttribute('aria-label'); },
            get labelledby() { return self.#container.getAttribute('aria-labelledby'); },
            set labelledby(v) { v ? self.#container.setAttribute('aria-labelledby', v) : self.#container.removeAttribute('aria-labelledby'); },
            get describedby() { return self.#container.getAttribute('aria-describedby'); },
            set describedby(v) { v ? self.#container.setAttribute('aria-describedby', v) : self.#container.removeAttribute('aria-describedby'); },
            focus: () => self.focus(),
            blur:  () => self.blur(),
            clear: () => self.clear(),
            get name() { return self.#input.name; },
            set name(v) { self.#input.name = v ?? ''; },
            get element() { return self.#container; },
            get destroyed() { return self.#destroyed; },
        };
    }

    /** Cleanup. */
    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        this.#closePopup();
        this.#eventAC?.abort();
        if (this.#container?.parentNode) this.#container.remove();
        if (this.#input) razyui(this.#input).css('display', '');
    }
};

export default DatePicker;
