/**
 * @fileoverview DatePicker helpers - pure utility functions.
 * @module module/DatePicker/helpers
 */

/**
 * Pad a number with leading zeros.
 *
 * @param {number} n
 * @param {number} [len=2]
 * @returns {string}
 */
export const pad = (n, len = 2) => String(n).padStart(len, '0');

/**
 * Compare two dates by year/month/day only (ignore time).
 *
 * @param {Date|null} a
 * @param {Date|null} b
 * @returns {boolean}
 */
export function sameDay(a, b) {
    if (!a || !b) return false;
    return a.getFullYear() === b.getFullYear() &&
        a.getMonth() === b.getMonth() &&
        a.getDate() === b.getDate();
}

/**
 * Number of days in a given month (0-indexed month).
 *
 * @param {number} year
 * @param {number} month - 0-indexed
 * @returns {number}
 */
export function daysInMonth(year, month) {
    return new Date(year, month + 1, 0).getDate();
}

/**
 * Parse a date string into a Date object.
 * Supports: HH:mm, YYYY-MM, YYYY-MM-DD, YYYY-MM-DD HH:mm.
 *
 * @param {string|null} str
 * @returns {Date|null}
 */
export function parseDate(str) {
    if (!str) return null;
    // Time only: HH:mm
    const t = /^(\d{1,2}):(\d{1,2})$/.exec(str.trim());
    if (t) return new Date(2000, 0, 1, +t[1], +t[2]);
    // Date with optional time
    const m = /^(\d{4})-(\d{1,2})(?:-(\d{1,2}))?(?:\s+(\d{1,2}):(\d{1,2}))?$/.exec(str.trim());
    if (!m) return null;
    return new Date(+m[1], +m[2] - 1, m[3] ? +m[3] : 1, m[4] ? +m[4] : 0, m[5] ? +m[5] : 0);
}

/**
 * Format a Date as a string for the given type.
 *
 * @param {Date|null} d
 * @param {string} type - 'date' | 'month' | 'datetime' | 'time'
 * @returns {string}
 */
export function formatDate(d, type) {
    if (!d) return '';
    if (type === 'month') return `${d.getFullYear()}-${pad(d.getMonth() + 1)}`;
    if (type === 'time') return `${pad(d.getHours())}:${pad(d.getMinutes())}`;
    if (type === 'datetime') return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())} ${pad(d.getHours())}:${pad(d.getMinutes())}`;
    return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}`;
}

/**
 * Test whether date `d` falls within the range [start, end] (inclusive, order-agnostic).
 *
 * @param {Date|null} d
 * @param {Date|null} start
 * @param {Date|null} end
 * @returns {boolean}
 */
export function inRange(d, start, end) {
    if (!d || !start || !end) return false;
    const t = d.getTime(), s = Math.min(start.getTime(), end.getTime()), e = Math.max(start.getTime(), end.getTime());
    return t >= s && t <= e;
}

/**
 * Clamp a date between optional min and max bounds.
 *
 * @param {Date|null} d
 * @param {Date|null} min
 * @param {Date|null} max
 * @returns {Date|null}
 */
export function clampDate(d, min, max) {
    if (!d) return d;
    if (min && d < min) return new Date(min);
    if (max && d > max) return new Date(max);
    return d;
}
