/**
 * @fileoverview DatePicker events - centralised event binding via AbortController.
 * @module module/DatePicker/events
 */

import razyui from '../../index.js';
import { CLS, TEXT } from './constants.js';

/**
 * Bind all static event listeners on DatePicker DOM elements.
 * Returns an AbortController - call `.abort()` to unbind all listeners.
 *
 * @param {object} domRefs - { container, segments, displayLabel, icon }
 * @param {object} handlers - callback map:
 *   onContainerClick, onDisplayLabelClick, onIconClick,
 *   onSegmentWheel, onSegmentFocus, onSegmentInput, onSegmentBlur, onSegmentKeydown
 * @returns {AbortController}
 */
export function bindEvents(domRefs, handlers) {
    const ac   = new AbortController();
    const opts = { signal: ac.signal };

    // Container click -> focus first segment
    razyui(domRefs.container).on('click', handlers.onContainerClick, opts);

    // Display label click (grid-filter context)
    if (domRefs.displayLabel) {
        razyui(domRefs.displayLabel).on('click', handlers.onDisplayLabelClick, opts);
    }

    // Icon button click (calendar or clock)
    if (domRefs.icon) {
        razyui(domRefs.icon).on('click', handlers.onIconClick, opts);
    }

    // Segment events
    for (const [key, inp] of Object.entries(domRefs.segments)) {
        const $inp = razyui(inp);
        $inp.on('wheel', (e) => handlers.onSegmentWheel(e, key),
            { signal: ac.signal, passive: false });
        $inp.on('focus',   () => handlers.onSegmentFocus(inp, key),   opts);
        $inp.on('input',   () => handlers.onSegmentInput(inp, key),   opts);
        $inp.on('blur',    () => handlers.onSegmentBlur(inp, key),    opts);
        $inp.on('keydown', (e) => handlers.onSegmentKeydown(e, inp, key), opts);
    }

    return ac;
}

/**
 * Attach a document-level outside-click listener for the popup.
 * Returns an AbortController - call `.abort()` to unbind.
 *
 * @param {HTMLElement} popup
 * @param {HTMLElement} container
 * @param {Function}    onClose - callback invoked on outside click
 * @returns {AbortController}
 */
export function attachPopupOutsideClick(popup, container, onClose) {
    const ac = new AbortController();
    razyui(document).on('mousedown', (e) => {
        if (!popup.contains(e.target) && !container.contains(e.target)) {
            onClose();
        }
    }, { signal: ac.signal });
    return ac;
}

/**
 * Bind popup-level keydown listener (Escape to close).
 *
 * @param {HTMLElement}     popup
 * @param {Function}        onEscape - callback invoked on Escape key
 * @param {AbortController} ac       - shared abort controller
 */
export function bindPopupKeydown(popup, onEscape, ac) {
    razyui(popup).on('keydown', (e) => {
        if (e.key === 'Escape') {
            onEscape();
        }
    }, { signal: ac.signal });
}

// ═══════════════════════════════════════
//  Popup Delegated Events
// ═══════════════════════════════════════

/**
 * Bind delegated event listeners on the popup container for all
 * interactive popup elements (nav buttons, title, grid cells, today button).
 *
 * Uses data-attributes set by view.js to extract context:
 *   - `data-drill` on title button -> view to drill into
 *   - `data-year`, `data-month`, `data-day` on day cells
 *   - `data-month-index`, `data-year` on month cells
 *   - `data-year` on year cells
 *
 * @param {HTMLElement} popupEl - the popup container element
 * @param {object} callbacks
 *   @param {Function} callbacks.onPrev          - navigate backward
 *   @param {Function} callbacks.onNext          - navigate forward
 *   @param {Function} callbacks.onTitleClick     - (newView: string) drill to view
 *   @param {Function} callbacks.onSelectDate     - (date: Date) select a date
 *   @param {Function} callbacks.onDayHover       - (date: Date) range hover preview
 *   @param {Function} callbacks.onTodayClick     - jump to today
 *   @param {Function} callbacks.onMonthSelect    - (monthIndex: number, year: number)
 *   @param {Function} callbacks.onYearDrillDown  - (year: number) drill to month view
 * @returns {AbortController}
 */
export function bindPopupEvents(popupEl, callbacks) {
    const ac   = new AbortController();
    const opts = { signal: ac.signal };

    const $popupEl = razyui(popupEl);

    // ── Click delegation ──
    $popupEl.on('click', (e) => {
        const btn = e.target.closest('button');
        if (!btn || !popupEl.contains(btn)) return;

        if (razyui(btn).hasClass(CLS.NAV)) {
            if (btn.getAttribute('aria-label') === TEXT.PREVIOUS) {
                callbacks.onPrev();
            } else {
                callbacks.onNext();
            }
        } else if (razyui(btn).hasClass(CLS.TITLE)) {
            const drill = btn.dataset.drill;
            if (drill) callbacks.onTitleClick(drill);
        } else if (razyui(btn).hasClass(CLS.DAY)) {
            const y = parseInt(btn.dataset.year, 10);
            const m = parseInt(btn.dataset.month, 10);
            const d = parseInt(btn.dataset.day, 10);
            if (!isNaN(d)) callbacks.onSelectDate(new Date(y, m, d));
        } else if (razyui(btn).hasClass(CLS.MONTH_CELL)) {
            const mi = parseInt(btn.dataset.monthIndex, 10);
            const yr = parseInt(btn.dataset.year, 10);
            if (!isNaN(mi)) callbacks.onMonthSelect(mi, yr);
        } else if (razyui(btn).hasClass(CLS.YEAR_CELL)) {
            const yr = parseInt(btn.dataset.year, 10);
            if (!isNaN(yr)) callbacks.onYearDrillDown(yr);
        } else if (razyui(btn).hasClass(CLS.TODAY_BTN)) {
            callbacks.onTodayClick();
        }
    }, opts);

    // ── Mouseover delegation (range hover preview) ──
    // mouseenter doesn't bubble - use mouseover with closest() check.
    $popupEl.on('mouseover', (e) => {
        const cell = e.target.closest('.' + CLS.DAY);
        if (!cell || !popupEl.contains(cell)) return;
        const y = parseInt(cell.dataset.year, 10);
        const m = parseInt(cell.dataset.month, 10);
        const d = parseInt(cell.dataset.day, 10);
        if (!isNaN(d) && callbacks.onDayHover) {
            callbacks.onDayHover(new Date(y, m, d));
        }
    }, opts);

    return ac;
}
