/**
 * @fileoverview DatePicker state - reactive state creation + disabled effect.
 * @module module/DatePicker/state
 */

import { CLS } from './constants.js';
import razyui from '../../index.js';

/**
 * Create the reactive state set for a DatePicker instance.
 *
 * @param {Function} stateFn - `razyui.state` factory
 * @param {HTMLInputElement} el - original input element
 * @returns {Array} stateSet - [stateRef, setState] with `.effect()` method
 */
export function createReactiveState(stateFn, el) {
    return stateFn({
        value: '',
        startDate: null,
        endDate: null,
        disabled: el.disabled,
        open: false,
    });
}

/**
 * Wire the disabled effect onto the reactive state.
 * Toggles the disabled class on the container and disables all segment inputs.
 *
 * @param {Array} stateSet - [stateRef, setState] with `.effect()`
 * @param {HTMLElement} container
 * @param {Object} segments - map of segment key -> input element
 */
export function wireDisabledEffect(stateSet, container, segments) {
    stateSet.effect(function () {
        razyui(container).toggleClass(CLS.DISABLED, !!this.disabled);
        Object.values(segments).forEach(inp => inp.disabled = !!this.disabled);
    });
}
